lemma LeftmostEmptyIs(rooms: seq<int>, i: int)
  requires 0 <= i < |rooms|
  requires rooms[i] == 0
  requires forall j :: 0 <= j < i ==> rooms[j] != 0
  ensures LeftmostEmpty(rooms) == i
  decreases i
{
